patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -8,7 +8,7 @@
   output reg [3:0] priority
 );

-  always @(req[0] or req[1] or req[2]) begin
+  always @(*) begin
     if (req[3])
       priority = 4'd3;
     else if (req[2])

before_code:
module priority_encoder(
  input [3:0] req,
  output reg [3:0] priority
);

  always @(req[0] or req[1] or req[2]) begin
    if (req[3])
      priority = 4'd3;
    else if (req[2])
      priority = 4'd2;
    else if (req[1])
      priority = 4'd1;
    else if (req[0])
      priority = 4'd0;
    else
      priority = 4'd15;
  end

endmodule

after_code:
module priority_encoder(
  input [3:0] req,
  output reg [3:0] priority
);

  always @(*) begin
    if (req[3])
      priority = 4'd3;
    else if (req[2])
      priority = 4'd2;
    else if (req[1])
      priority = 4'd1;
    else if (req[0])
      priority = 4'd0;
    else
      priority = 4'd15;
  end

endmodule
